#!/usr/bin/env node

/**
 * Generate structured narrative content for each region using Anthropic Claude.
 *
 * This produces four distinct content blocks per region (editorial_overview,
 * best_time_to_visit, what_makes_distinct, vertical_highlights) stored in the
 * region_narratives table. These complement the existing long-form editorial
 * prose already generated by generate-region-editorial.mjs.
 *
 * Usage:
 *   node --env-file=.env.local scripts/generate-region-narratives.mjs
 *
 * Optional flags:
 *   --slug=barossa-valley   Generate for a single region
 *   --force                 Regenerate even if content_hash matches
 *   --dry-run               Print prompts without calling API
 *
 * Cost: ~$0.01 per region (Haiku, ~800 tokens out).
 * Total for 47 regions: ~$0.50.
 */

import { createClient } from '@supabase/supabase-js'
import crypto from 'crypto'
import dotenv from 'dotenv'

// Load env BEFORE importing Anthropic SDK — override: true needed
// because dotenvx preload may set empty ANTHROPIC_API_KEY
dotenv.config({ path: '.env.local', override: true })

const { default: Anthropic } = await import('@anthropic-ai/sdk')

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
)

const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY })

const args = process.argv.slice(2)
const singleSlug = args.find(a => a.startsWith('--slug='))?.split('=')[1]
const force = args.includes('--force')
const dryRun = args.includes('--dry-run')

const VERTICAL_LABELS = {
  sba: 'Small Batch Atlas (wineries, breweries, distilleries)',
  fine_grounds: 'Fine Grounds Atlas (specialty coffee)',
  collection: 'Collection Atlas (museums, galleries, heritage)',
  craft: 'Craft Atlas (makers, studios, artisans)',
  rest: 'Rest Atlas (boutique accommodation)',
  field: 'Field Atlas (nature, walks, swimming holes)',
  corner: 'Corner Atlas (independent shops)',
  found: 'Found Atlas (vintage, op shops, secondhand)',
  table: 'Table Atlas (restaurants, cafes, food producers)',
}

const SYSTEM_PROMPT = `You are writing editorial content for Australian Atlas, a network of nine curated directories mapping independent Australia. Write in an informed, place-specific, quietly opinionated voice. Never sound like a tourism brochure or listicle. Draw ONLY on the verified listing data provided — never introduce venues, attributes, or claims not in the context.

Generate four distinct JSON blocks:
{
  "editorial_overview": "120-word editorial overview of this region, grounded in what the listing data reveals about its character",
  "best_time_to_visit": "50-80 words about when to visit, inferred from the types of venues present (e.g. wine regions peak in autumn, coastal areas in summer)",
  "what_makes_distinct": "80-120 words identifying what makes this region genuinely different from neighbouring regions, based on listing patterns",
  "vertical_highlights": [
    { "vertical": "sba", "listing_name": "...", "note": "One sentence editorial note" },
    ...
  ]
}

Rules:
- Only include verticals in vertical_highlights that have at least one listing
- The editorial_overview should name specific places from the listing data
- Do not use superlatives without substance
- Do not include verticals with zero listings in any block`

/**
 * Approximate bounding box radius (in degrees) from a map zoom level.
 * Matches the same lookup used by the region page itself.
 */
function zoomToRadiusDeg(zoom) {
  const lookup = { 6: 3.0, 7: 1.5, 8: 0.75, 9: 0.5, 10: 0.3, 11: 0.15, 12: 0.08 }
  return lookup[zoom] || 0.5
}

/**
 * Fetch all active listings for a region using the same two-strategy approach
 * as the region page: bounding box first, text-match fallback.
 */
async function getRegionListings(region) {
  // Primary: geographic bounding box
  if (region.center_lat && region.center_lng) {
    const radius = zoomToRadiusDeg(region.map_zoom || 9)
    const { data } = await supabase
      .from('listings')
      .select('id, vertical, name, slug, description, region, state, is_featured, editors_pick')
      .eq('status', 'active')
      .not('lat', 'is', null)
      .not('lng', 'is', null)
      .gte('lat', region.center_lat - radius)
      .lte('lat', region.center_lat + radius)
      .gte('lng', region.center_lng - radius)
      .lte('lng', region.center_lng + radius)
      .limit(200)
    if (data && data.length > 0) return data
  }

  // Fallback: text match on region name
  let query = supabase
    .from('listings')
    .select('id, vertical, name, slug, description, region, state, is_featured, editors_pick')
    .eq('status', 'active')

  if (region.state) {
    query = query.eq('state', region.state)
  }

  query = query.or(`region.ilike.%${region.name}%,address.ilike.%${region.name}%`)

  const { data } = await query.limit(200)
  return data || []
}

/**
 * Build a structured context string from listing data for the LLM prompt.
 * Groups by vertical, includes names, truncated descriptions, and known_for
 * where available.
 */
function buildContextObject(region, listings) {
  const byVertical = {}
  for (const l of listings) {
    if (!byVertical[l.vertical]) byVertical[l.vertical] = []
    byVertical[l.vertical].push(l)
  }

  const verticalBreakdown = []
  for (const [v, items] of Object.entries(byVertical)) {
    const label = VERTICAL_LABELS[v] || v
    const listingDetails = items.slice(0, 10).map(l => {
      const parts = [l.name]
      if (l.description) {
        // Truncate description to ~40 words
        const words = l.description.split(/\s+/)
        parts.push(words.slice(0, 40).join(' ') + (words.length > 40 ? '...' : ''))
      }
      return parts.join(' — ')
    })

    verticalBreakdown.push({
      vertical: v,
      label,
      count: items.length,
      listings: listingDetails,
    })
  }

  return {
    region_name: region.name,
    state: region.state,
    description: region.description,
    total_listings: listings.length,
    verticals: verticalBreakdown,
  }
}

/**
 * Compute MD5 hash of the context object to detect data changes.
 */
function hashContext(contextObj) {
  const serialized = JSON.stringify(contextObj)
  return crypto.createHash('md5').update(serialized).digest('hex')
}

/**
 * Call Anthropic API with the structured context and parse JSON response.
 */
async function generateNarrative(region, contextObj) {
  const contextStr = JSON.stringify(contextObj, null, 2)

  const userPrompt = `Generate structured narrative content for the ${region.name} region (${region.state}).

REGION CONTEXT:
${contextStr}

Respond with ONLY valid JSON matching the schema described in the system prompt. No markdown fences, no preamble.`

  if (dryRun) {
    console.log(`  [dry-run] Context: ${contextObj.total_listings} listings across ${contextObj.verticals.length} verticals`)
    console.log(`  [dry-run] Prompt length: ${userPrompt.length} chars`)
    return null
  }

  const response = await anthropic.messages.create({
    model: 'claude-haiku-4-5-20241022',
    max_tokens: 1024,
    system: SYSTEM_PROMPT,
    messages: [{ role: 'user', content: userPrompt }],
  })

  const text = response.content[0].text.trim()

  // Strip markdown fences if present
  const cleaned = text.replace(/^```json?\s*/i, '').replace(/\s*```$/i, '')

  try {
    const parsed = JSON.parse(cleaned)

    // Validate required fields
    if (!parsed.editorial_overview || !parsed.best_time_to_visit || !parsed.what_makes_distinct) {
      throw new Error('Missing required fields in response')
    }

    // Estimate cost: Haiku input ~$0.001/1K tokens, output ~$0.005/1K tokens
    const inputTokens = response.usage?.input_tokens || 0
    const outputTokens = response.usage?.output_tokens || 0
    const cost = (inputTokens * 0.001 + outputTokens * 0.005) / 1000
    console.log(`  Tokens: ${inputTokens} in / ${outputTokens} out (~$${cost.toFixed(4)})`)

    return parsed
  } catch (err) {
    throw new Error(`Failed to parse JSON response: ${err.message}\nRaw: ${text.substring(0, 200)}`)
  }
}

/**
 * Upsert narrative record into region_narratives.
 */
async function upsertNarrative(regionId, narrative, contentHash, listingCount) {
  const { error } = await supabase
    .from('region_narratives')
    .upsert({
      region_id: regionId,
      editorial_overview: narrative.editorial_overview,
      best_time_to_visit: narrative.best_time_to_visit,
      what_makes_distinct: narrative.what_makes_distinct,
      vertical_highlights: narrative.vertical_highlights || [],
      listing_count_at_generation: listingCount,
      content_hash: contentHash,
      generated_at: new Date().toISOString(),
    }, {
      onConflict: 'region_id',
    })

  if (error) throw error
}

async function main() {
  console.log('Region Narrative Generator')
  console.log('==========================\n')

  // Fetch regions
  let query = supabase
    .from('regions')
    .select('id, name, slug, state, description, center_lat, center_lng, map_zoom')
    .order('name')

  if (singleSlug) {
    query = query.eq('slug', singleSlug)
  }

  const { data: regions, error } = await query

  if (error) {
    console.error('Failed to fetch regions:', error)
    process.exit(1)
  }

  if (!regions || regions.length === 0) {
    console.log(singleSlug ? `No region found with slug: ${singleSlug}` : 'No regions found')
    process.exit(0)
  }

  // Fetch existing narratives for hash comparison
  const { data: existingNarratives } = await supabase
    .from('region_narratives')
    .select('region_id, content_hash')

  const existingHashMap = {}
  for (const n of (existingNarratives || [])) {
    existingHashMap[n.region_id] = n.content_hash
  }

  console.log(`Found ${regions.length} region(s)`)
  if (dryRun) console.log('[DRY RUN MODE — no API calls will be made]\n')
  if (force) console.log('[FORCE MODE — regenerating all regardless of hash]\n')

  let generated = 0
  let skipped = 0
  let failed = 0
  let noListings = 0
  let totalCost = 0

  for (const region of regions) {
    console.log(`\n[${region.slug}] ${region.name}`)

    try {
      // 1. Fetch listings
      const listings = await getRegionListings(region)

      if (listings.length === 0) {
        console.log('  Skipped: no active listings')
        noListings++
        continue
      }

      // 2. Build context and hash
      const contextObj = buildContextObject(region, listings)
      const contentHash = hashContext(contextObj)

      // 3. Check if hash matches (skip if unchanged, unless --force)
      if (!force && existingHashMap[region.id] === contentHash) {
        console.log(`  Skipped: data unchanged (${listings.length} listings, hash ${contentHash.substring(0, 8)})`)
        skipped++
        continue
      }

      console.log(`  ${listings.length} listings across ${contextObj.verticals.length} verticals`)

      // 4. Generate narrative
      const narrative = await generateNarrative(region, contextObj)

      if (dryRun) {
        generated++
        continue
      }

      // 5. Upsert
      await upsertNarrative(region.id, narrative, contentHash, listings.length)
      console.log('  Saved to region_narratives')
      generated++

      // Small delay between API calls
      await new Promise(r => setTimeout(r, 300))

    } catch (err) {
      console.log(`  ERROR: ${err.message}`)
      failed++
    }
  }

  // Summary
  console.log('\n==========================')
  console.log(`Done: ${generated} generated, ${skipped} unchanged, ${noListings} no listings, ${failed} failed`)
  if (!dryRun && generated > 0) {
    console.log(`Estimated total cost: ~$${(generated * 0.01).toFixed(2)} (Haiku)`)
  }
}

main()
